<?php
 namespace League\CommonMark\Block\Parser; use League\CommonMark\Block\Element\ThematicBreak; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; use League\CommonMark\Util\RegexHelper; final class ThematicBreakParser implements BlockParserInterface { public function parse(ContextInterface $context, Cursor $cursor): bool { if ($cursor->isIndented()) { return false; } $match = RegexHelper::matchAt(RegexHelper::REGEX_THEMATIC_BREAK, $cursor->getLine(), $cursor->getNextNonSpacePosition()); if ($match === null) { return false; } $cursor->advanceToEnd(); $context->addBlock(new ThematicBreak()); $context->setBlocksParsed(true); return true; } } 